// ============================================================
// STEP: Calculate Engagement Score
// Formula: ((likes×1) + (comments×3) + (shares×5)) / max(views,1)
// Shares and comments are weighted higher — they signal stronger intent.
// Returns only the #1 highest-engagement trend for the MVP.
// ============================================================

if (!items || items.length === 0) {
  throw new Error('No trends returned from Apify. Check actor ID and API token.');
}

const scored = items.map(item => {
  const d = item.json;

  // Normalise field names across different Apify TikTok actor versions
  const likes    = d.diggCount    || d.likes         || d.likesCount    || 0;
  const comments = d.commentCount || d.comments      || d.commentsCount || 0;
  const shares   = d.shareCount   || d.shares        || d.sharesCount   || 0;
  const views    = Math.max(d.playCount || d.views   || d.viewsCount    || 0, 1);

  const engagement_score = ((likes * 1) + (comments * 3) + (shares * 5)) / views;

  return {
    json: {
      video_url:        d.webVideoUrl || d.videoUrl || d.url || 'N/A',
      caption:          d.text || d.caption || d.description || '',
      hashtags:         d.hashtags || [],
      author:           (d.authorMeta && d.authorMeta.name) || d.author || d.username || '',
      views,
      likes,
      comments,
      shares,
      created_at:       d.createTimeISO || d.createTime || new Date().toISOString(),
      engagement_score: parseFloat(engagement_score.toFixed(6))
    }
  };
});

// Sort descending and take top 1
scored.sort((a, b) => b.json.engagement_score - a.json.engagement_score);

if (!scored[0]) {
  throw new Error('Engagement scoring produced no results.');
}

return [scored[0]];

// ============================================================
// STEP: Build OpenAI Request Body
// Constructs the full chat completions request.
// The AI is explicitly instructed NOT to copy original videos.
// Returns the full request object — the HTTP node sends it as JSON.
// ============================================================

const trend = items[0].json;

const systemPrompt =
  'You are a creative short-form video strategist specializing in viral TikTok ' +
  'content for product recommendations and affiliate marketing. ' +
  'You analyze trending content and create ORIGINAL video concepts inspired by ' +
  'trends — never copying them. ' +
  'You always respond with valid JSON only. No markdown, no extra text outside the JSON.';

const jsonSchema = JSON.stringify({
  trend_summary:       'Brief description of why this trend is popular',
  video_title:         'Catchy, original title (under 60 chars)',
  video_angle:         'Unique hook that differentiates this video',
  target_audience:     'Who this video is for',
  product_category:    'Category of products to recommend',
  suggested_products:  ['Product 1', 'Product 2', 'Product 3'],
  voiceover_script:    'Full voiceover script for a 15-45 second video',
  scene_descriptions:  ['Scene 1 description', 'Scene 2 description', 'Scene 3 description'],
  on_screen_text:      ['Text overlay 1', 'Text overlay 2', 'Text overlay 3'],
  caption:             'TikTok caption with emojis (under 150 chars)',
  hashtags:            ['hashtag1', 'hashtag2', 'hashtag3', 'hashtag4', 'hashtag5']
}, null, 2);

const userPrompt =
  'Analyze this trending TikTok post and create an ORIGINAL video concept inspired by it.\n\n' +
  'IMPORTANT: Do not copy the original video. Use it only as inspiration. Create a new, original video.\n\n' +
  'Trend Data:\n' +
  '- Caption: ' + trend.caption + '\n' +
  '- Hashtags: ' + JSON.stringify(trend.hashtags) + '\n' +
  '- Views: ' + trend.views + '\n' +
  '- Likes: ' + trend.likes + '\n' +
  '- Comments: ' + trend.comments + '\n' +
  '- Shares: ' + trend.shares + '\n' +
  '- Engagement Score: ' + trend.engagement_score + '\n\n' +
  'Create an original product recommendation video inspired by this trend.\n' +
  'Return ONLY valid JSON matching this exact structure:\n' +
  jsonSchema;

return [{
  json: {
    model: 'gpt-4o',
    temperature: 0.8,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user',   content: userPrompt }
    ]
  }
}];

// ============================================================
// STEP: Parse AI Response
// Extracts the JSON video concept from OpenAI's response.
// Validates that all required fields are present.
// ============================================================

const response = items[0].json;

if (!response.choices || response.choices.length === 0) {
  throw new Error('OpenAI returned no choices. Response: ' + JSON.stringify(response));
}

const raw = response.choices[0].message.content;

let idea;
try {
  idea = JSON.parse(raw);
} catch (e) {
  throw new Error('AI response is not valid JSON. Content: ' + raw.substring(0, 500));
}

// Validate required fields
const required = [
  'video_title', 'voiceover_script', 'scene_descriptions',
  'on_screen_text', 'caption', 'hashtags', 'product_category', 'suggested_products'
];
for (const field of required) {
  if (!idea[field]) {
    throw new Error('AI response missing required field: ' + field);
  }
}

// Ensure array fields are arrays
idea.scene_descriptions  = Array.isArray(idea.scene_descriptions)  ? idea.scene_descriptions  : [];
idea.on_screen_text      = Array.isArray(idea.on_screen_text)      ? idea.on_screen_text      : [];
idea.suggested_products  = Array.isArray(idea.suggested_products)  ? idea.suggested_products  : [];
idea.hashtags            = Array.isArray(idea.hashtags)            ? idea.hashtags            : [];

return [{ json: idea }];

// ============================================================
// STEP: Build Creatomate Request Body
// Maps AI-generated video concept to Creatomate template fields.
// Adjust element names here if your template uses different names.
// ============================================================

const idea = items[0].json;

const modifications = {
  // Text overlays — match exact element names in your Creatomate template
  'video_title':       idea.video_title       || '',
  'scene_1_text':      (idea.scene_descriptions[0] || '').substring(0, 200),
  'scene_2_text':      (idea.scene_descriptions[1] || '').substring(0, 200),
  'scene_3_text':      (idea.scene_descriptions[2] || '').substring(0, 200),
  'on_screen_text_1':  (idea.on_screen_text[0]     || '').substring(0, 100),
  'on_screen_text_2':  (idea.on_screen_text[1]     || '').substring(0, 100),
  'product_category':  idea.product_category  || '',
  'product_name':      (idea.suggested_products[0] || ''),
  'cta_text':          'Shop Now 🛍️',
  // Voiceover — Creatomate can generate TTS from script text
  // Remove this field if your template does not include a voiceover element
  'voiceover':         idea.voiceover_script  || ''
};

return [{
  json: {
    template_id:   $env.CREATOMATE_TEMPLATE_ID,
    output_format: 'mp4',
    // Vertical 9:16 format for TikTok/Reels
    width:  1080,
    height: 1920,
    modifications
  }
}];

// ============================================================
// STEP: Extract Render ID from Creatomate Response
// Creatomate returns an array of render objects.
// We extract the render ID for status polling.
// ============================================================

const response = items[0].json;

// Creatomate returns an array
const render = Array.isArray(response) ? response[0] : response;

if (!render || !render.id) {
  throw new Error('No render ID in Creatomate response: ' + JSON.stringify(response));
}

return [{
  json: {
    render_id:     render.id,
    render_status: render.status,
    render_url:    render.url || null
  }
}];

// ============================================================
// STEP: Build Telegram Message
// Constructs the approval message with rendered video details.
// The $execution.resumeUrl is the unique URL that resumes the
// waiting workflow when visited.
// ============================================================

const idea    = $node['Parse AI Response'].json;
const render  = $node['Check Render Status'].json;
const trend   = $node['Calculate Engagement Score'].json;

const approveUrl = $execution.resumeUrl + '?approved=true';
const rejectUrl  = $execution.resumeUrl + '?approved=false';

const hashtags = (idea.hashtags || []).map(h => '#' + h).join(' ');
const products = (idea.suggested_products || []).map((p, i) => `${i + 1}. ${p}`).join('\n');

const message =
  '🎬 *New Video Ready for Approval*\n\n' +
  `*Title:* ${idea.video_title}\n` +
  `*Category:* ${idea.product_category}\n` +
  `*Audience:* ${idea.target_audience}\n` +
  `*Angle:* ${idea.video_angle}\n\n` +
  `*Caption Preview:*\n${idea.caption}\n\n` +
  `*Hashtags:* ${hashtags}\n\n` +
  `*Suggested Products:*\n${products}\n\n` +
  `*Trend Engagement Score:* ${trend.engagement_score}\n\n` +
  `🎥 *Rendered Video URL:*\n${render.url}\n\n` +
  '━━━━━━━━━━━━━━━━━━━━━\n' +
  `✅ [APPROVE](${approveUrl})\n` +
  `❌ [REJECT](${rejectUrl})\n` +
  '━━━━━━━━━━━━━━━━━━━━━\n' +
  '_Click a link above to resume the workflow_';

return [{
  json: {
    chat_id:    $env.TELEGRAM_CHAT_ID,
    text:       message,
    parse_mode: 'Markdown'
  }
}];

// ============================================================
// STEP: Build Upload-Post Request Body
// Publishes the generated video to TikTok via Upload-Post API.
// Add 'instagram', 'facebook', 'youtube' to platforms[] in future.
// ============================================================

const idea   = $node['Parse AI Response'].json;
const render = $node['Check Render Status'].json;

const caption  = idea.caption  || '';
const hashtags = (idea.hashtags || []).map(h => h.startsWith('#') ? h : '#' + h);

// Full caption with hashtags appended
const fullCaption = caption + '\n\n' + hashtags.join(' ');

return [{
  json: {
    account_id:  $env.UPLOAD_POST_ACCOUNT_ID,
    platforms:   ['tiktok'],
    video_url:   render.url,
    caption:     fullCaption,
    hashtags:    idea.hashtags || [],
    schedule:    'now'
    // To schedule for later: replace 'now' with ISO 8601 timestamp
    // e.g. schedule: '2025-01-15T14:00:00Z'
    //
    // Future platforms (disabled for MVP):
    // platforms: ['tiktok', 'instagram', 'youtube']
  }
}];

// ============================================================
// STEP: Build Google Sheets Log Row
// Logs a full record of this run to Google Sheets.
// Columns (must exist in row 1 of your sheet):
//   date | trend_url | engagement_score | generated_video_url |
//   caption | product_category | approval_status |
//   publish_status | publish_url | video_title | products
// ============================================================

const now    = new Date().toISOString();
const idea   = $node['Parse AI Response'].json;
const trend  = $node['Calculate Engagement Score'].json;
const render = $node['Check Render Status'].json;
const pub    = items[0].json;  // Upload-Post response

return [{
  json: {
    values: [[
      now,
      trend.video_url         || '',
      trend.engagement_score  || '',
      render.url              || '',
      idea.caption            || '',
      idea.product_category   || '',
      'APPROVED',
      pub.status              || pub.state || 'submitted',
      pub.post_url            || pub.url   || '',
      idea.video_title        || '',
      (idea.suggested_products || []).join(', ')
    ]]
  }
}];

// ============================================================
// STEP: Log Rejection
// Records that the video was rejected in Telegram.
// Extend this node to also log to Google Sheets if needed.
// ============================================================

const idea  = $node['Parse AI Response'].json;
const trend = $node['Calculate Engagement Score'].json;

console.log('Video REJECTED:', idea.video_title);

return [{
  json: {
    status:       'rejected',
    timestamp:    new Date().toISOString(),
    video_title:  idea.video_title || '',
    trend_url:    trend.video_url  || '',
    reason:       'Manual rejection via Telegram'
  }
}];

// ============================================================
// STEP: Handle Render Failure
// Called when Creatomate render did not return status='succeeded'.
// Check render_status for 'failed', 'error', or still 'rendering'.
// ============================================================

const renderData = items[0].json;

console.error('Creatomate render did not succeed. Status:', renderData.status);

return [{
  json: {
    status:        'render_failed',
    timestamp:     new Date().toISOString(),
    render_id:     $node['Extract Render ID'].json.render_id || '',
    render_status: renderData.status        || 'unknown',
    error_message: renderData.errorMessage  || renderData.error || 'No error message returned'
  }
}];
